let DU = part2.pa_Diameter;

  if (DU == 2.5 || DU == 3 || DU == 4 || DU == 5 || DU == 6 || DU == 8 || DU == 8 || DU == 10 || DU == 15 || DU == 35) {

    let Drill = this.addncout_DrillVert();

    // StandardValue
    Drill.nc_TOOL = "102";
    Drill.nc_XA = posRel.x + (part2.pa_Diameter/2);
    Drill.nc_YA = partSelf._dimz - posRel.z - (part2.pa_Diameter/2);
    Drill.nc_AN = 1;
    Drill.nc_Side = "Top";
    Drill.nc_MprRelevant = true;
    Drill.nc_DrawingRelevant = true;


    // AttributeValues

    Drill.nc_TI = part2.pa_DrillDepth;
    Drill.nc_DU = part2.pa_Diameter;
    Drill.nc_BM = part2.pa_DrillDepth >= partSelf._thickness ? "LSL" : "LS";
    Drill.nc_WI = 0;
    Drill.nc_AB = 1;
    //Drill.nc_LA = 0;
    Drill.nc_MI = 0;
    Drill.nc_KO = "00";
  }   
  else {
    let Pocket = this.addncout_Pocket();

    //StandardValue

    Pocket.nc_TOOL = "112";
    Pocket.nc_XA = posRel.x;
    Pocket.nc_YA = partSelf._dimy - posRel.y;
    //Pocket.nc_Side = "Front";
    Pocket.nc_MprRelevant = true;
    Pocket.nc_DrawingRelevant = true;

    Pocket.nc_BR = DU;
    Pocket.nc_KO = "00";
    Pocket.nc_LA = DU;
    Pocket.nc_RD = DU / 2;
    Pocket.nc_TI = part2.pa_DrillDepth;

  }

